import { useEffect, useRef, useState } from "react";
import { lerp, clamp, ease } from "./helpers";

export default function Question() {
  const [progress, setProgress] = useState(0);
  const sectionRef = useRef(null);

  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current; if (!el) return;
      const rect = el.getBoundingClientRect();
      const p = clamp(-rect.top / (el.offsetHeight - window.innerHeight), 0, 1);
      setProgress(p);
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const titleP = ease(clamp(progress / 0.30, 0, 1));

  const questions = [
    { img: "/assets/question1.png", text: "Which segments are the most risk-prone?" },
    { img: "/assets/question2.png", text: "Where are the risk hotspots across the country?" },
    { img: "/assets/question3.png", text: "what correlations exist between risk rates and other factors?" },
  ];

  return (
    <div ref={sectionRef} style={{ height: "250vh", position: "relative" }}>
      <div style={{
        position: "sticky", top: 0, height: "100vh", overflow: "hidden",
        background: `radial-gradient(ellipse 70% 80% at 100% 50%, rgba(28,67,185,0.55) 0%, transparent 65%), #0d0d0d`,
        display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center",
        padding: "80px 48px",
      }}>
        {/* Title */}
        <h2 style={{
          fontFamily: "'Inter','Helvetica Neue',sans-serif",
          fontSize: "clamp(44px,6.5vw,100px)",
          fontWeight: 800, color: "white",
          margin: "0 0 56px", textAlign: "center", lineHeight: 1.08,
          maxWidth: 1200,
          opacity: titleP, transform: `translateY(${lerp(30, 0, titleP)}px)`,
        }}>
          This section<br />
          <span style={{ fontWeight: 900 }}>answers questions like</span>
        </h2>

        {/* Cards */}
        <div style={{
          display: "grid", gridTemplateColumns: "repeat(3,1fr)",
          gap: 20, width: "100%", maxWidth: 1300,
        }}>
          {questions.map((q, i) => {
            const cardP = ease(clamp((progress - 0.15 - i * 0.08) / 0.30, 0, 1));
            return (
              <div key={i} style={{
                background: "rgba(255,255,255,0.06)",
                border: "1px solid rgba(255,255,255,0.12)",
                borderRadius: 16, padding: "28px",
                display: "flex", alignItems: "center", gap: 20,
                opacity: cardP,
                transform: `translateY(${lerp(40, 0, cardP)}px) scale(${lerp(0.95, 1, cardP)})`,
                transition: "box-shadow 0.3s",
              }}>
                <div style={{
                  width: 80, height: 80, flexShrink: 0,
                  background: "rgba(255,255,255,0.08)",
                  borderRadius: 14,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  overflow: "hidden",
                }}>
                  <img src={q.img} alt="" style={{ width: 52, height: 52, objectFit: "contain" }} />
                </div>
                <p style={{
                  color: "white", fontSize: "clamp(14px,1.15vw,19px)",
                  fontWeight: 500, margin: 0, lineHeight: 1.55,
                  fontFamily: "'Inter',sans-serif",
                }}>{q.text}</p>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
